-- ============================================
-- Legislacao full-site: jorginho-mello / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2019-2022
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/5350/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2019_2022_20260506
--
-- Filtro factual: endpoint senador/5350/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=5350
--   com NumOrdemAutor=1. Resultado deste snapshot: 77 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'jorginho-mello';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'jorginho-mello: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('140051', '135205', '135193', '135195', '135194', '135198', '135200', '135206', '135202', '135207', '135212', '135223', '135353', '135679', '136303', '136642', '136870', '136866', '136919', '137040', '137277', '137441', '137634', '138194', '138727', '139264', '139380', '139425', '140239', '135203', '135209', '135699', '137122', '137846', '139975', '141845', '141122', '141123', '141304', '141363', '141561', '145238', '145453', '145872', '146055', '140516', '141271', '143646', '143751', '144419', '145597', '149584', '146254', '146473', '147423', '147424', '147570', '148494', '148501', '149200', '149838', '150073', '150493', '150494', '147899', '149582', '149583', '150492', '150946', '151076', '152024', '152574', '152934', '154239', '154463', '153100', '153703');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('140051', '135205', '135193', '135195', '135194', '135198', '135200', '135206', '135202', '135207', '135212', '135223', '135353', '135679', '136303', '136642', '136870', '136866', '136919', '137040', '137277', '137441', '137634', '138194', '138727', '139264', '139380', '139425', '140239', '135203', '135209', '135699', '137122', '137846', '139975', '141845', '141122', '141123', '141304', '141363', '141561', '145238', '145453', '145872', '146055', '140516', '141271', '143646', '143751', '144419', '145597', '149584', '146254', '146473', '147423', '147424', '147570', '148494', '148501', '149200', '149838', '150073', '150493', '150494', '147899', '149582', '149583', '150492', '150946', '151076', '152024', '152574', '152934', '154239', '154463', '153100', '153703')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jorginho-mello: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'SC'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2022
    AND COALESCE(hp.periodo_fim, 9999) >= 2019;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao jorginho-mello: mandato Senado/SC 2019-2022 nao encontrado em historico_politico';
  END IF;
END $$;

