    ('PL', '5575', 2020, 'Altera a Lei nº 13.999, de 18 de maio de 2020, que institui o Programa Nacional de Apoio às Microempresas e Empresas de Pequeno Porte (Pronampe), para o desenvolvimento e o fortalecimento dos pequenos negócios; e altera as Leis nos 13.636, de 20 de março de 2018, 10.735, de 11 de setembro de 2003, e 9.790, de 23 de março de 1999, para permitir o uso desse programa, de forma permanente, como política oficial de crédito, dando o devido tratamento diferenciado e favorecido as micro e pequenas empresas, visando consolidar os pequenos negócios como agentes de sustentação, transformação e desenvolvimento da economia nacional.', 'Senado', '146055', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/146055', 'jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2022_20260506', '{"proposicao_id_api":"146055","descricao_identificacao":"PL 5575/2020","data_apresentacao":"2020-12-17","casa":"SF","codigo_parlamentar_senado":5350,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PL","uf_autor_no_protocolo":"SC","autor_nome":"Jorginho Mello","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/5350/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/146055.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/146055.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/146055","coverage_id":"jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2022_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"jorginho-mello-senado-lote-a-20260506","snapshot_consulta_em":"2026-05