    ('PL', '1869', 2021, 'Altera a Lei nº 12.651, de 25 de maio de 2012, que dispõe sobre a proteção da vegetação nativa; altera as Leis nºs 6.938, de 31 de agosto de 1981, 9.393, de 19 de dezembro de 1996, e 11.428, de 22 de dezembro de 2006; revoga as Leis nºs 4.771, de 15 de setembro de 1965, e 7.754, de 14 de abril de 1989, e a Medida Provisória nº 2.166-67, de 24 de agosto de 2001; e dá outras providências, e altera a lei 6.766, de 19 de dezembro de 1979, que dispõe sobre o Parcelamento do Solo Urbano e dá outras Providências, para regulamentar as faixas marginais de quaisquer cursos d´água natural em áreas urbanas consolidadas. .', 'Senado', '148501', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/148501', 'jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2022_20260506', '{"proposicao_id_api":"148501","descricao_identificacao":"PL 1869/2021","data_apresentacao":"2021-05-19","casa":"SF","codigo_parlamentar_senado":5350,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PL","uf_autor_no_protocolo":"SC","autor_nome":"Jorginho Mello","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/5350/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/148501.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/148501.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/148501","coverage_id":"jorginho-mello-senado-completo-autoria-substantiva-2019-2022-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2022_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"jorginho-mello-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T07:01: